//! Ratify Protocol — C/C++ FFI bindings.
//!
//! Exposes the Ratify Protocol Rust SDK as a C-compatible ABI producing:
//! - `libratify_c.a`  — static library for embedded/RTOS targets
//! - `libratify_c.so` / `.dylib` / `.dll` — shared library
//!
//! The C header (`include/ratify.h`) is generated by cbindgen and committed so
//! consumers do not need the Rust toolchain to use the pre-built artifacts.
//!
//! ## Two verify paths
//!
//! - `ratify_verify_bundle` — simple path: scope + clock override.
//! - `ratify_verify_bundle_opts` — full path: revocation, geo/speed/amount/rate
//!   constraints, session-context binding, stream-context binding.
//!
//! ## Memory model
//!
//! Every function returning a heap-allocated object returns an opaque pointer.
//! Free it with the matching `ratify_*_free`. NULL is always safe to pass to
//! free functions. Double-free is undefined behaviour; the library does not
//! guard against it.
//!
//! ## Error handling
//!
//! Fallible functions write a heap-allocated, null-terminated UTF-8 string to
//! `*err_out` when `err_out` is non-NULL. Always free with `ratify_error_free`.
//! The returned `RatifyStatus` is authoritative; `err_out` carries detail only.
//!
//! ## Thread safety
//!
//! All functions are stateless and re-entrant. The library holds no global
//! mutable state. Concurrent calls from different threads are safe provided
//! each thread owns its own handles. The revocation and rate-counter callbacks
//! you supply must themselves be thread-safe if you call from multiple threads.
//!
//! ## Fixed-size buffers
//!
//! Several fields (`challenge`, `session_context`, `stream_id`) are exactly
//! 32 bytes — a protocol invariant (SPEC §6). Every pointer to such a field
//! is accompanied by a `*_len: usize` parameter or field. Pass the exact byte
//! count; the library returns `RatifyErrBadArgument` if the count is wrong.

#![allow(clippy::missing_safety_doc)]
#![allow(deprecated)] // VerifyOptions.is_revoked is deprecated; we use revocation provider

pub mod advanced;
pub use advanced::*;

// ============================================================================
// Custom entropy source (for embedded targets without OS RNG)
// ============================================================================
// When compiled with feature = "custom-entropy", the getrandom crate will
// call ratify_custom_getrandom() to obtain random bytes instead of using
// the OS entropy source. The application MUST call ratify_set_entropy_source()
// before any call to ratify_challenge_generate() or ratify_delegation_issue().
// See README.md for the full embedded entropy setup guide.
#[cfg(feature = "custom-entropy")]
mod entropy {
    use std::sync::atomic::{AtomicUsize, Ordering};

    static ENTROPY_FN: AtomicUsize = AtomicUsize::new(0);

    /// Register a custom entropy callback for platforms without OS-level RNG.
    ///
    /// `callback` must:
    /// - Write exactly `len` cryptographically random bytes to `buf`.
    /// - Return 0 on success, non-zero if insufficient entropy is available
    ///   (the library will panic rather than use weak randomness).
    /// - Be thread-safe if `ratify_*` functions are called from multiple threads.
    ///
    /// Call this once at startup, before any delegation or challenge operation.
    /// On FreeRTOS with an STM32 TRNG:
    ///   ```c
    ///   int my_entropy(uint8_t *buf, size_t len) {
    ///       for (size_t i = 0; i < len; i += 4) {
    ///           uint32_t rnd;
    ///           if (HAL_RNG_GenerateRandomNumber(&hrng, &rnd) != HAL_OK) return -1;
    ///           memcpy(buf + i, &rnd, (len - i < 4) ? len - i : 4);
    ///       }
    ///       return 0;
    ///   }
    ///   ratify_set_entropy_source(my_entropy);
    ///   ```
    #[no_mangle]
    pub extern "C" fn ratify_set_entropy_source(
        callback: unsafe extern "C" fn(buf: *mut u8, len: usize) -> i32,
    ) {
        ENTROPY_FN.store(callback as usize, Ordering::SeqCst);
    }

    /// Called by getrandom when feature = "custom-entropy" is enabled.
    /// Dispatches to the registered callback or panics if none is registered.
    pub fn custom_getrandom(buf: &mut [u8]) -> Result<(), getrandom::Error> {
        let fn_ptr = ENTROPY_FN.load(Ordering::SeqCst);
        if fn_ptr == 0 {
            panic!(
                "ratify: no entropy source registered. \
                 Call ratify_set_entropy_source() before generating challenges or certs. \
                 See README.md §Custom Entropy."
            );
        }
        let f: unsafe extern "C" fn(*mut u8, usize) -> i32 =
            unsafe { std::mem::transmute(fn_ptr) };
        let result = unsafe { f(buf.as_mut_ptr(), buf.len()) };
        if result == 0 {
            Ok(())
        } else {
            Err(getrandom::Error::UNSUPPORTED)
        }
    }

    // Register our custom_getrandom as the getrandom backend.
    getrandom::register_custom_getrandom!(custom_getrandom);
}

