// ============================================================================
// Status codes
// ============================================================================

/// Return codes for all fallible Ratify C API functions.
///
/// Values 0–7 are reserved for the current version. A C `switch` must include
/// a `default` case; future versions may add values.
#[repr(C)]
#[derive(Debug, PartialEq, Clone, Copy)]
pub enum RatifyStatus {
    /// Operation succeeded.
    RatifyOk = 0,
    /// A required pointer argument was NULL.
    RatifyErrNullPointer = 1,
    /// JSON parsing or serialisation failed.
    RatifyErrJson = 2,
    /// Cryptographic operation failed (bad key material, invalid signature,
    /// or entropy unavailable).
    RatifyErrCrypto = 3,
    /// A size argument was invalid (e.g., `buf_len` != 32 for a 32-byte field).
    RatifyErrBadArgument = 4,
    /// An internal error that should not occur in normal operation.
    RatifyErrInternal = 5,
    /// A required argument contained invalid UTF-8.
    RatifyErrEncoding = 6,
}

// ============================================================================
// Callback function types (documented here; inlined in structs for cbindgen)
// ============================================================================
//
// RatifyRevocationFn: unsafe extern "C" fn(*const c_char, *mut c_void) -> c_int
//   cert_id — null-terminated hex string of the cert being checked
//   userdata — opaque pointer from RatifyVerifyOptions.revocation_userdata
//   Returns: 1=revoked, 0=not revoked, -1=lookup error (fail-closed → invalid)
//
// RatifyRateCountFn: unsafe extern "C" fn(*const c_char, i64, *mut c_void) -> i64
//   cert_id  — null-terminated hex string
//   window_s — rolling window in seconds
//   userdata — opaque pointer from RatifyVerifierContext.rate_userdata
//   Returns: number of invocations of cert_id in the last window_s seconds

// ============================================================================
// VerifierContext — constraint evaluation inputs
// ============================================================================

/// Application-supplied inputs for evaluating first-class constraints.
///
/// Zero-initialise (`{0}` in C99) all fields you do not use. The verifier
/// fails closed with `constraint_unverifiable` when a required field is absent.
///
/// ```c
/// RatifyVerifierContext ctx = {0};
/// ctx.current_lat  = 47.6062;
/// ctx.current_lon  = -122.3321;
/// ctx.has_location = 1;
/// ```
#[repr(C)]
pub struct RatifyVerifierContext {
    // --- Geo (required by geo_circle, geo_polygon, geo_bbox) ---
    pub current_lat: c_double,
    pub current_lon: c_double,
    pub current_alt_m: c_double,
    /// 1 if the geo fields above are populated, 0 to skip geo evaluation.
    pub has_location: c_int,

    // --- Speed (required by max_speed_mps) ---
    pub current_speed_mps: c_double,
    /// 1 if speed is populated.
    pub has_speed: c_int,

    // --- Transaction amount (required by max_amount) ---
    pub requested_amount: c_double,
    /// Null-terminated ISO 4217 currency code (e.g. "USD"). NULL = no amount.
    pub requested_currency: *const c_char,
    /// 1 if amount fields are populated.
    pub has_amount: c_int,

    // --- Rate counter (required by max_rate) ---
    /// Returns how many times `cert_id` was exercised in the last `window_s`
    /// seconds. NULL = skip rate evaluation (constraint fails closed).
    /// The `cert_id` pointer is only valid for the duration of the callback.
    pub rate_fn: Option<unsafe extern "C" fn(
        cert_id: *const c_char,
        window_s: i64,
        userdata: *mut std::ffi::c_void,
    ) -> i64>,
    /// Passed back to `rate_fn`.
    pub rate_userdata: *mut std::ffi::c_void,
}

// ============================================================================
// Stream context
// ============================================================================

/// Verifier-tracked stream context for v1.1 stream-bound bundles.
///
/// Required when the bundle carries `stream_id` and `stream_seq`. Set
/// `last_seen_seq = 0` for the first turn (no prior accepted turn).
///
/// `stream_id` MUST point to exactly 32 bytes; `stream_id_len` MUST be 32.
/// Any other value returns `RatifyErrBadArgument`.
#[repr(C)]
pub struct RatifyStreamContext {
    /// Pointer to exactly 32 bytes of stream ID.
    pub stream_id: *const c_uchar,
    /// Must be exactly 32. Validated at runtime.
    pub stream_id_len: usize,
    /// Highest sequence number already accepted for this stream (0 = first turn).
    pub last_seen_seq: i64,
}

// ============================================================================
// Full verify options
// ============================================================================

/// Full verification options for `ratify_verify_bundle_opts`.
///
/// Zero-initialise (`{0}`) unused fields.
///
/// ```c
/// RatifyVerifyOptions opts = {0};
/// opts.required_scope      = "meeting:attend";
/// opts.revocation_fn       = my_revocation_callback;
/// opts.revocation_userdata = my_db_handle;
/// // Session binding: opts.session_context + opts.session_context_len = 32
/// ```
#[repr(C)]
pub struct RatifyVerifyOptions {
    /// Scope the bundle must include. NULL or empty string = no scope check.
    pub required_scope: *const c_char,

    /// Fixed Unix timestamp (seconds) for expiry and freshness checks.
    /// 0 = use the system clock. Pass `(int64_t)time(NULL)` for current time.
    /// Note: timestamp 0 (Unix epoch, 1970-01-01) is interpreted as "system clock",
    /// not as the literal year 1970. Embedded systems without a synchronised RTC
    /// should set this explicitly from their best available clock source.
    pub now_unix: i64,

    /// Pointer to `session_context_len` bytes of session context for v1.1
    /// session binding. NULL = no session binding.
    /// When set, `session_context_len` MUST be exactly 32.
    pub session_context: *const c_uchar,
    /// Must be 0 (no session binding) or 32. Any other value returns
    /// `RatifyErrBadArgument`.
    pub session_context_len: usize,

    /// Revocation callback. NULL = no revocation check (unsafe without RevocationProvider).
    /// Signature: int fn(const char *cert_id, void *userdata)
    /// Returns:  1 = revoked (bundle rejected),
    ///           0 = not revoked (verification continues),
    ///          -1 = lookup error (bundle rejected with identity_status=invalid, fail-closed).
    pub revocation_fn: Option<unsafe extern "C" fn(
        cert_id: *const c_char,
        userdata: *mut std::ffi::c_void,
    ) -> c_int>,
    /// Passed back to every `revocation_fn` call.
    pub revocation_userdata: *mut std::ffi::c_void,

    /// Constraint evaluation inputs. NULL = no constraint context; any cert
    /// bearing a geo/speed/amount/rate constraint will fail closed.
    pub context: *const RatifyVerifierContext,

    /// Stream context for v1.1 stream-bound bundles. NULL = no stream validation.
    pub stream: *const RatifyStreamContext,
}

